INSERT INTO `author_requests` VALUES (1,'Eiichiro Oda','Male','ru-- chitamahale180904@gmail.com','scrypt:32768:8:1$XxGu0KSjtQAj8DcX$c96e0d6dd6e631fb03a2c3c8ed973a8f3b221ed243437ca29b652d851a5ab228ee40f957b4760f0e5034cc47c23453f48202f66658f438138ed43ad423399a3d','Eiichiro Oda is a Japanese manga artist best known as the creator of One Piece, one of the most successful manga series of all time. Born in Kumamoto, Japan, he showed an early interest in drawing and storytelling and began his professional career in his late teens. Oda gained major recognition after One Piece debuted in 1997. He is praised for his imaginative world-building, memorable characters, and emotional storytelling. The series has broken multiple records, cementing OdaŌĆÖs influence in modern manga culture.','1975-01-01','approved','2025-12-29 11:21:09','2025-12-29 11:24:40'),(2,'Eiichiro Oda','Male','ruchitamahale180904@gmail.com','scrypt:32768:8:1$XxGu0KSjtQAj8DcX$c96e0d6dd6e631fb03a2c3c8ed973a8f3b221ed243437ca29b652d851a5ab228ee40f957b4760f0e5034cc47c23453f48202f66658f438138ed43ad423399a3d','Eiichiro Oda is a Japanese manga artist best known as the creator of One Piece, one of the most successful manga series of all time. Born in Kumamoto, Japan, he showed an early interest in drawing and storytelling and began his professional career in his late teens. Oda gained major recognition after One Piece debuted in 1997. He is praised for his imaginative world-building, memorable characters, and emotional storytelling. The series has broken multiple records, cementing OdaŌĆÖs influence in modern manga culture.','1975-01-01','approved','2025-12-29 11:21:09','2025-12-29 11:24:40'),(3,'lowen','Female','lowen@gmail.com','scrypt:32768:8:1$LObgEVGmCrDEoZ6f$2946633dcd52adadf3dbd6a5c23002f90a7d070492a6dede86c64c2a867fffed8084d5991bbba0a28f647c518c80286af86681f065b68fb44da8f99848b58f67','hii its good to meet you fdjfkdjfkldsjfkldsfjkdsfjkdlfjdsklfjsdklfjsdkkkkkkkkkkkkkkkkkkkkkkkkkkkkkdfsdnkldsnfnvfvnmcxvnsfjoh f