INSERT INTO `series` VALUES (1,'Harry Potter','Fantasy series about a young wizard and his adventures at Hogwarts.'),(2,'Game of Thrones','Epic fantasy series set in the Seven Kingdoms of Westeros.'),(3,'Twisted','Contemporary romance series by Ana Huang.'),(4,'Shiva Trilogy','Indian mythological fantasy series about Lord Shiva.'),(5,'The Hunger Games','Dystopian young adult series set in Panem.'),(6,'The Lord of the Rings','Epic high-fantasy trilogy.'),(7,'Standalone','Books not part of a series.'),(8,'ACOTAR','A Court of Thorns and Roses fantasy romance series.'),(9,'Mistborn','Epic fantasy series by Brandon Sanderson.'),(10,'Percy Jackson','Greek mythology-based YA fantasy series.'),(11,'Divergent','YA dystopian series by Veronica Roth.'),(12,'Hercule Poirot','Mystery series featuring the Belgian detective Hercule Poirot.'),(13,'Sherlock Holmes','Classic detective stories featuring Sherlock Holmes and Dr. Watson.'),(14,'Dune Saga','Epic science fiction series set in the distant future.'),(15,'Kings Of Sins','The Kings of Sin series features seven billionaire, morally gray ŌĆ£Kings,ŌĆØ each inspired by a deadly sin, and the women who become their weakness. Every book delivers intense chemistry, high heat, emotional drama, and dark, addictive romance. Each story follows a new couple and can be read as a standalone.'),(16,'Gods Of The Game','Gods of the Game is a steamy sports romance series centered on elite, superstar athletes known as the ŌĆ£Gods,ŌĆØ each with fame, talent, and flaws that make them irresistible. Every book follows a different athlete and the woman who challenges him, blending high heat, drama, emotional tension, and the glamourŌĆöand darknessŌĆöof professional sports. Each story can be read as a standalone.'),(17,'If Love','The If Love series is a set of interconnected contemporary romances following friends navigating college, careers, heartbreak, and second chances. Each book focuses on a different couple and blends emotional tension, slow-burn chemistry, drama, and personal growth. Light, heartfelt, and addictive, the series explores love, friendship, and finding yourself, and each book can be read as a standalone.'),(18,'Slammed','A heartfelt new-adult romance following Layken and Will, two young people dealing with grief, family responsibilities, and a forbidden connection that tests their strength. Expect emotional twists, poetry slams, and a journey of love, loss, and healing.'),(19,'Hopeless','A deep, emotional series centered on Sky and Holder as they uncover buried trauma, dark secrets, and a past that connects them in shocking ways. It explores heartbreak, healing, identity, and second chances, with companion stories showing different perspectives.'),(20,'Maybe','A mix of music, friendship, and complicated love, this duet follows Sydney, Ridge, and their tangled relationships as they navigate loyalty, emotional conflict, and creative connection. A blend of angst, melodies, and messy, real-life love.'),(21,'It Ends With Us','A powerful, emotional journey exploring love, heartbreak, and breaking generational cycles. LilyŌĆÖs relationship with Ryle and reconnection with Atlas create a story about strength, survival, and choosing better. The duet follows healing, closure, and new beginnings.'),(22,'Never Never','A mystery romance about two teens who lose their memories repeatedly and must uncover the truth behind their connection, their past, and the strange force affecting them. A blend of suspense, drama, love, and shocking twists.');
/*!40000 ALTER TABLE `series` ENABLE KEYS */;
UNLOCK TABLES;

