CREATE TABLE `user_genres` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `genre_id` int NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`,`genre_id`),
  KEY `genre_id` (`genre_id`),
