INSERT INTO `users` VALUES (1,'admin101','Administration','A','mruchita38@gmail.com','scrypt:32768:8:1$YS2iAcvhwiCf9J25$da6617fbf2cbe7663b68b59132001e858049ecda9f9962ebad96fb185014137bc218719e39e4cc03974a50e17d8753292fab9b43a066d1f70b150e3d39133c43','2025-11-24 06:59:52',NULL,NULL,NULL,NULL,NULL,NULL,'Admin'),(2,'ChauhanGautam04','Gautam','Chauhan','chauhangautam176@gmail.com','scrypt:32768:8:1$TfnjkExfrH8YUeBg$303f8192a2b5f3370a774970d8ad421be65b4ef1130430d705f947fc1eae501a4fdbb142c7315603a420f189b2b49ab1fbe447de11c336780557bd4214dc207b','2025-11-24 07:01:56','Lover of soft romances, rainy days, and the smell of old books','Hi! IŌĆÖm someone who finds comfort in fictional worlds, warm coffee, and slow mornings. I adore romance, light fantasy, and beautifully written stories that stay with you. Recommend me books that feel like a warm hug.','Male','2005-07-23','Student','\\static\\images\\gautam.png','Reader'),(3,'ruchita73','Ruchita','Mahale','ruchi04ta@gmail.com','scrypt:32768:8:1$NrUDHRgccfHbH2zE$f46363595203e9514efdd591d10b34204ff16337b622d8b9de5fd8d19438f8ddb87986706dccc316bbbbec472d285c8b870c9bcf5a8106563c9805b0a74084f1','2025-11-24 07:24:12','In love with morally grey characters and twisted plots','I enjoy books that leave me thinking long after I finish them. Dark romance, thrillers, and mysteries are my escape. I love unpredictable endings, intense chemistry, and intricate storylines. The darker, the better.','Female','2004-09-18','Student of Computer Science','\\static\\images\\ruchita.jpg','Admin'),(4,'netra89','Netra','Patel','netrajigneshpatel@gmail.com','scrypt:32768:8:1$A6PaPuhCkvpX29dk$343be23cd92bd796bb0813c99d4af022bdc5d0a56dc8b811267e29e24e2c2d85db46512caa6564f43bf4eed51e783d5a502bad59407f5ddbb8196cec15acf9e8','2025-11-24 07:25:42','Reader ŌĆó Dreamer ŌĆó Story Collector','I love reading romance, fiction, and thrillers. I enjoy emotional stories, character-driven plots, and books that make me feel something. Always looking for my next favourite re